index 842881156dc6..cb44735ac8d1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -1860,9 +1860,24 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
         return CastInst::Create(Instruction::ZExt, NarrowMaxMin, II->getType());
       }
     }
-    // If both operands of unsigned min/max are sign-extended, it is still ok
-    // to narrow the operation.
-    [[fallthrough]];
+
+    // umax(x <<nuw 1, x + 1) --> x == 0 ? 1 : x <<nuw 1
+    // because 2*x >= x+1 for all unsigned x != 0.
+    Value *Shl;
+    if (match(I0, m_NUWShl(m_Value(X), m_One())) &&
+        match(I1, m_c_Add(m_Specific(X), m_One())))
+      Shl = I0;
+    else if (match(I1, m_NUWShl(m_Value(X), m_One())) &&
+             match(I0, m_c_Add(m_Specific(X), m_One())))
+      Shl = I1;
+    else {
+      // If both operands of unsigned min/max are sign-extended, it is still ok
+      // to narrow the operation.
+      [[fallthrough]];
+    }
+
+    Value *IsZero = Builder.CreateICmpEQ(X, Constant::getNullValue(X->getType()));
+    return SelectInst::Create(IsZero, ConstantInt::get(II->getType(), 1), Shl);
   }
